var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>익명으로 수신한 메일입니다.</color>`,JPN:`<color=#ffd34c>匿名の送信者から受信したメールです。</color>`,ENG:`<color=#ffd34c>An anonymous mail arrived.</color>`,TWN:`<color=#ffd34c>匿名收取的郵件</color>`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`조사대가 연구를 마치고 복귀했다.`,JPN:`調査隊が研究を終えて戻ってきた。`,ENG:`Our investigation team returned safely after finishing up their research.`,TWN:`調查隊完成調查後回去了。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`다만, 귀사의 직원이 우리 측 인력과 접촉을 시도했다는 보고를 받았다.`,JPN:`ただ、そちらの社員が、こちらの人員と接触しようとしたという報告を受けた。`,ENG:`However, I received a report that one of your employees tried to get in contact with our men.`,TWN:`只是，我們收到了貴公司的員工試圖和我們的人員進行接觸的報告。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`귀하가 의도한 일은 아니겠지만, 다음부터는 사전에 직원들을 단속해 주길 바란다.`,JPN:`そちらが意図したことではないだろうが、今後は社員管理の徹底をお願いしたい。`,ENG:`I'm sure you did not intend for this to happen, but please try to keep your people under control next time.`,TWN:`雖然這可能不是閣下的意圖，但希望下次你能事前管教好你的員工們。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`이번 건을 잘 처리해 준 대가로 추가 보수를 입금했다. 유용하게 쓰길 바란다.`,JPN:`今回の件をうまく処理してもらった対価として、
追加報酬を入金した。有効に活用していただきたい。`,ENG:`I have, however, deposited a bonus payment for a job well done. I hope you make good use of it.`,TWN:`由於這次任務處理得很好，我為你增加了一些報酬，希望你能好好使用。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};